124	
125		const binDir = fs.mkdtempSync(path.join(os.tmpdir(), 'ddx-graph-e2e-bin-'));
126		ddxBinary = path.join(binDir, process.platform === 'win32' ? 'ddx-e2e.exe' : 'ddx-e2e');
127		const result = spawnSync('go', ['build', '-o', ddxBinary, '.'], {
128			cwd: CLI_DIR,
