138	async function freePort(): Promise<number> {
139		return new Promise((resolve, reject) => {
140			const server = net.createServer();
141			server.once('error', reject);
142			server.listen(0, '127.0.0.1', () => {
143				const address = server.address();
144				if (!address || typeof address === 'string') {
145					server.close(() => reject(new Error('could not allocate port')));
146					return;
147				}
148				const port = address.port;
149				server.close(() => resolve(port));
150			});
151		});
152	}
