250	async function stopRealDdxServer(server: RealServer) {
251		await server.api.dispose();
252		if (server.process.exitCode === null) {
253			server.process.kill();
254			await Promise.race([
255				new Promise((resolve) => server.process.once('exit', resolve)),
256				new Promise((resolve) => {
257					setTimeout(() => {
258						if (server.process.exitCode === null) server.process.kill('SIGKILL');
259						resolve(undefined);
260					}, 2000);
261				})
262			]);
263		}
264		fs.rmSync(server.root, { recursive: true, force: true });
265	}
