523				function parseRgb(s: string): [number, number, number, number] {
524					const m = s.match(/rgba?\(([^)]+)\)/i);
525					if (!m) return [0, 0, 0, 1];
526					const parts = m[1].split(',').map((p) => parseFloat(p.trim()));
527					return [parts[0], parts[1], parts[2], parts[3] === undefined ? 1 : parts[3]];
528				}
529				function blend(
530					fg: [number, number, number],
531					alpha: number,
532					bg: [number, number, number]
533				): [number, number, number] {
534					return [
535						fg[0] * alpha + bg[0] * (1 - alpha),
536						fg[1] * alpha + bg[1] * (1 - alpha),
537						fg[2] * alpha + bg[2] * (1 - alpha)
538					];
