563				const arrowCs = getComputedStyle(arrow);
564				const stroke = parseRgb(lineCs.stroke);
565				const strokeOpacity = parseFloat(lineCs.strokeOpacity || '1');
566				const fill = parseRgb(arrowCs.fill);
567				const canvas = bgRgb as [number, number, number];
568	
